sql:
SELECT project_id, project_name, project_description
FROM projects
WHERE reduction_factor >= 0.8 AND status = 'in progress';

SELECT SUM(p.reduction_factor) AS TotalReductionFactor
FROM projects p
JOIN structural_components sc ON p.project_id = sc.project_id
JOIN nonstructural_components nsc ON p.project_id = nsc.project_id
WHERE sc.structural_value = (
    SELECT MAX(structural_value) FROM structural_components
) AND nsc.nonstructural_value = (
    SELECT MIN(nonstructural_value) FROM nonstructural_components
);

SELECT * 
FROM projects 
WHERE project_manager_id IS NULL;

SELECT DISTINCT p.macro_taxonomy
FROM projects p
JOIN users u ON p.project_manager_id = u.user_id;

SELECT content_id, contents_value, content_name, content_description, content_type, last_updated
FROM project_contents
WHERE project_id = 'id_of_the_project';

external_knowledge:
- "captains" metaphorically refers to project managers;
- "colossal vessels" metaphorically refers to projects with large budgets;
- "trimmed the sails" metaphorically refers to reducing the impact through mitigation strategies.

sql:
SELECT component_id, component_name 
FROM nonstructural_components 
WHERE last_updated > '2023-04-01';

SELECT first_name, role
FROM users
WHERE user_id = (SELECT project_manager_id FROM projects WHERE project_name = 'Project A');

SELECT component_name, component_description, impact_type
FROM nonstructural_components
WHERE component_id = 0;

external_knowledge:
- "substantial progress in mitigation" is interpreted as a reduction factor greater than 0.75;
- "latest components" refer to those implemented within the last 12 months;
- "big picture classifications" refer to the macro taxonomy of the project.

